INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f9273851-df82-45cb-a8f5-cc62ef4f43f9',
  '00000000-0000-0000-0000-000000000001',
  $escape$OWASP — Mastering Burp Suite: Intercepting Proxy, Repeater, Scanner$escape$,
  $escape$OWASP's Burp Suite is a comprehensive security testing tool. The intercepting proxy captures and modifies HTTP traffic, allowing you to manipulate requests and responses. The repeater tool enables you to send requests multiple times with different parameters. The scanner automatically identifies vulnerabilities. Active scanning sends requests to the target server, while passive scanning observes traffic without interacting with the server. When using Burp Suite with OWASP's ZAP, you can combine the strengths of both tools.$escape$,
  NULL,
  NULL,
