INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7a66eb6c-f8b5-4da4-b707-8c5fe3a154fb',
  '00000000-0000-0000-0000-000000000001',
  $escape$Owasp Logging Strategy — What to Log, What Not to Log, SIEM Integration$escape$,
  $escape$Owasp's ESAPI (Enterprise Security API) recommends logging sensitive information such as user input, session IDs, and authentication tokens. However, personally identifiable information (PII) like credit card numbers and social security numbers should be redacted or hashed. For SIEM (Security Information and Event Management) integration, use the W3C Extended Log Format to standardize log data. This enables correlation and analysis across systems. Consider using ESAPI's Logger class to handle logging, which provides features like log levels and filtering.$escape$,
  $escape$import { Logger } from 'owasp-esapi-java';
const logger = new Logger();
logger.log(LoggingLevel.INFO, 'User logged in with session ID ' + sessionId);
logger.log(LoggingLevel.ERROR, 'Authentication failed with error code ' + errorCode);$escape$,
  $escape$java$escape$,
