INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '619506e1-3707-432a-afce-1eebfc9e7601',
  '00000000-0000-0000-0000-000000000001',
  $escape$Owasp: Shift Left Security with Dependency Check$escape$,
  $escape$To integrate security checks early in the development lifecycle using Owasp, utilize the Dependency-Check plugin. This plugin scans your project's dependencies for known vulnerabilities and provides a report. You can configure it to run at the CI/CD pipeline level, ensuring timely detection of vulnerabilities. For example, with a Maven project, add the dependency-check-maven-plugin to your pom.xml.$escape$,
  $escape$plugin>
        <groupId>org.owasp</groupId>
        <artifactId>dependency-check-maven-plugin</artifactId>
        <executions>
            <execution>
                <goals>
                    <goal>check</goal>
                </goals>
            </execution>
        </executions>
    </plugin>
$escape$,
  $escape$xml$escape$,
