INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '8b9448b0-7053-456b-8026-7363cec888bd',
  '00000000-0000-0000-0000-000000000001',
  $escape$OWASP: Enhancing Semgrep Rules with Custom Patterns$escape$,
  $escape$Semgrep, an open-source static analysis tool, is integrated with OWASP's ZAP to fortify web application security. To craft effective custom rules, familiarize yourself with Semgrep's pattern syntax. For instance, to identify SQL injection vulnerabilities, define a pattern that matches suspicious input. The `semgrep` CLI tool allows you to create and verify custom rules. You can also tap into the Semgrep community's repository of pre-built rules, tailored for OWASP-specific security checks. To integrate custom Semgrep rules into your CI/CD pipeline, utilize the Semgrep API or the OWASP ZAP plugin.$escape$,
  NULL,
  NULL,
